import { IPoi, PoiKind, PoiCost } from './poi.types';

/**
 * Mock POI dataset focused on the Intermountain West corridor (I-5, I-15,
 * I-70, I-80, I-90, US-101). ~50 of each kind. Mirrors iOverlander's
 * "Last Verified" date, Campendium's cell-signal field, and Sanidumps'
 * cost clarity.
 *
 * All photos arrays are empty for v1 — the modal renders a kind-glyph
 * placeholder when photos.length === 0.
 */

// Helper to keep the seed compact.
function poi(
  id: string,
  kind: PoiKind,
  name: string,
  lat: number,
  lng: number,
  address: string,
  cost: PoiCost,
  priceNote: string | undefined,
  lastVerified: string,
  amenities: string[],
  extras: Partial<IPoi> = {},
): IPoi {
  return { id, kind, name, lat, lng, address, photos: [], cost, priceNote, lastVerified, amenities, ...extras };
}

