/** POIs whose coords fall inside a bounding box (north/south/east/west). */
export function poisInBounds(
  pois: IPoi[],
  bounds: { north: number; south: number; east: number; west: number },
): IPoi[] {
  return pois.filter(p =>
    p.lat <= bounds.north && p.lat >= bounds.south
    && p.lng <= bounds.east && p.lng >= bounds.west,
  );
}

export function poisByKind(pois: IPoi[], kinds: Set<PoiKind>): IPoi[] {
  if (kinds.size === 0) return [];
  return pois.filter(p => kinds.has(p.kind));
}
